const WithPreviews = () => {
    const [files, setFiles] = useState<(File & { preview: string })[]>([]);

    const handleFilesChange = (newFiles: File[]) => {
      setFiles(newFiles.map((file) => Object.assign(file, {
        preview: URL.createObjectURL(file),
      })));
    };

    return (
        <>
            <DBoxFile
                accept={{}}
                onDrop={handleFilesChange}
                onLoad={handleFilesChange}
                multiple>Drop files here to see previews
                        </DBoxFile>
            <aside className="d-flex flex-wrap gap-2 mt-3">
                {files.map((file) => (
                  <div key={file.name} className="text-center">
                    <img
                      src={file.preview}
                      alt={file.name}
                      className="img-thumbnail"
                      style={{
                        width: '100px',
                        height: '100px',
                        objectFit: 'cover',
                      }}
                      onLoad={() => URL.revokeObjectURL(file.preview)}
                    />
                    <p
                      className="small text-muted"
                      style={{
                        width: '100px',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                      }}
                    >
                      {file.name}
                    </p>
                  </div>
                ))}
            </aside>
        </>
    );
};

