function Default(props: ComponentProps<typeof DDatePicker>) {
  const {
    value,
    onChange,
    selected,
    ...rest
  } = useMemo(() => props, [props]);

  const [date, setDate] = useState<Date | null>(value ? new Date(value) : new Date());

  const handleDate = useCallback((newDate: Date | null) => {
    setDate(newDate);
  }, []);

  useEffect(() => {
    if (value) {
      handleDate(new Date(value));
    }
  }, [value, handleDate]);

  return (
    <DDatePicker
      {...rest}
      key={JSON.stringify(props, null, 0)}
      selected={date}
      onChange={(newDate: Date | null) => setDate(newDate)}
      showHeaderSelectors
    />
  );
}

