import {
  Meta,
  ArgTypes,
  Stories,
} from '@storybook/addon-docs/blocks';

import * as DCurrencyTextStories from './DCurrencyText.stories';

# Currency Text

Component to format and display a currency value using a `DContextProvider` to get the config.

